\documentclass[11pt]{beamer}
\usetheme{CambridgeUS}
\usecolortheme{beaver}
\setbeamertemplate{navigation symbols}{}
\usepackage{graphicx}
\usepackage{amsmath}
\usepackage{booktabs}
\title[ESG Preference]{ESG Preference, Institutional Trading, and Stock Return Patterns}
\author{Jie Cao, Sheridan Titman, Xintong Zhan, Weiming Zhang}
\institute{Journal of Financial and Quantitative Analysis, Vol. 58, No. 5}
\date{March 2024 Lecture}

\begin{document}

\begin{frame}
  \titlepage
\end{frame}

\begin{frame}{Motivation}
  \begin{itemize}
    \item ESG investing soared after 2004 while ESG data coverage expanded rapidly.
    \item Socially responsible (SR) institutions focus on ESG-preferred stocks, limiting their attention set.
    \item Research question: How do ESG tastes shape institutional trading and observable return patterns?
  \end{itemize}
  \begin{figure}
    \centering
    \includegraphics[width=0.75\textwidth]{output/figures/esg-investing-growth.pdf}
    \caption{Assets allocated to ESG investing (log $\$bn$).}
  \end{figure}
\end{frame}

\begin{frame}{Data \& Key Measures}
  \begin{itemize}
    \item Returns/prices/volumes: CRSP; ESG scores: MSCI ESG KLD Stats (annual updates) and firm fundamentals.
    \item \textbf{SR_IO}: share of aggregate holdings held by SR institutions, defined relative to ESG score cutoffs.
    \item \textbf{SUE score}: standardized unexpected earnings over past 3 months – captures near-term mispricing.
    \item \textbf{SYY score}: composite mispricing score (opposite direction) combining 11 anomaly signals.
  \end{itemize}
  \begin{figure}
    \centering
    \includegraphics[width=0.7\textwidth]{output/figures/esg-coverage-time.pdf}
    \caption{Coverage of ESG scores across CRSP stocks.}
  \end{figure}
\end{frame}

\begin{frame}{Hypotheses and Mechanism}
  \begin{itemize}
    \item SR institutions prefer high ESG firms and hence monitor a narrower universe.
    \item Hypothesis 1: SR trading reacts less to signals outside their ESG universe, leading to limited attention effects.
    \item Hypothesis 2: SR holdings predict future returns once we condition on ESG preference and mispricing signals.
    \item Mechanism: ESG preference constrains trading, slowing price discovery for non-ESG firms yet improving predictability within the ESG set.
  \end{itemize}
\end{frame}

\begin{frame}{Trading Behavior: Table 2 Summary}
  \begin{itemize}
    \item Panel A: SR vs. non-SR responses to the SUE signal – SR institutions adjust ownership/number of institutions less aggressively.
    \item Panel B: SYY signal yields similar pattern, confirming robustness across mispricing proxies.
    \item Significance reported with Newey-West t-statistics; *** indicates 1\%, ** 5\%, * 10\% levels.
    \item Interpretation: SR investors concentrate on ESG-preferred stocks, limiting the breadth of their trading signals.
  \end{itemize}
\end{frame}

\begin{frame}{Return Patterns \& Period Comparison}
  \begin{itemize}
    \item Table 3: Double sorts on SR_IO and mispricing (SUE/SYY) show higher long-short spreads for high SR_IO portfolios.
    \item Table 4: Comparing 1996–2003 to 2004–2016, ESG preference emerges in the later period with stronger alphas.
    \item Long-short alphas imply ESG demand shapes returns, especially as ESG investing goes mainstream.
  \end{itemize}
\end{frame}

\begin{frame}{Robustness: Funding Liquidity \& Price Efficiency}
  \begin{itemize}
    \item Table 5: SR_IO interacts with funding liquidity — SR stocks in illiquid times show muted trading responses.
    \item Table 6: Price delay regressions (Hou \& Moskowitz, 2005) show SR holdings correlate with slower incorporation of information.
    \item Table 7: Short-sale characteristics indicate higher ESG attention and fewer short attacks among high-SR firms.
  \end{itemize}
\end{frame}

\begin{frame}{Additional Robustness}
  \begin{itemize}
    \item Table 8: Investment horizon matters — SR investors with shorter horizons show sharper responsiveness.
    \item Table 9: SR active mutual funds replicate the pattern; high SR_MO portfolios yield larger alphas.
    \item Table 10: Alternative SR definitions (Asset4 ESG scores) confirm the result.
  \end{itemize}
  \begin{figure}
    \centering
    \includegraphics[width=0.75\textwidth]{output/figures/esg-score-distribution.pdf}
    \caption{ESG score distributions: low vs. high SR_IO groups.}
  \end{figure}
\end{frame}

\begin{frame}{Triple Sorts \& Size Interactions (Tables 11-12)}
  \begin{itemize}
    \item Table 11: Triple sorts on SR_IO, ESG score, and SYY show high SR/ESG portfolios deliver persistent alphas.
    \item Table 12: Size-sorted portfolios reveal the role of firm size — ESG preference affects small and large firms differently across periods.
    \item Implication: ESG demand interacts with several characteristics, reinforcing the limited attention story.
  \end{itemize}
\end{frame}

\begin{frame}{Conclusion}
  \begin{itemize}
    \item ESG preference shapes institutional trading and return predictability via limited attention and concentrated holdings.
    \item Policy relevance: monitoring ESG coverage and managing concentration risk is critical as ESG investing scales.
    \item Empirical takeaway: ESG-focused capital slows price discovery outside the ESG set but enhances predictability within it.
  \end{itemize}
\end{frame}

\end{document}

